import React from 'react';
import { Link } from 'react-router-dom';
import { useAuth } from '../auth/AuthContext';
import heroNetwork from '../assets/hero-network.svg';

function LandingPage() {
  const { auth } = useAuth();
  const startRoute = auth?.token ? '/dashboard' : '/auth';

  return (
    <section className="landing-simple section-wrap">
      <div className="landing-simple-copy">
        <p className="eyebrow">CareFlow</p>
        <h1>Simple, fast coordination for urgent donation requests.</h1>
        <p>
          One place for hospital teams to raise, route, and track critical requests.
        </p>
        <div className="landing-actions">
          <Link to={startRoute} className="btn-solid">Start</Link>
          <Link to="/how-it-works" className="btn-ghost">How It Works</Link>
        </div>
        <p className="landing-simple-note">Secure verification. Live updates. Clean workflow.</p>
      </div>
      <div className="landing-simple-visual">
        <img
          src={heroNetwork}
          alt="CareFlow network connecting hospitals and coordination teams"
          className="hero-visual"
        />
      </div>
    </section>
  );
}

export default LandingPage;
